def _get_category_by_id(category_id: int):
    for c in CATEGORIES:
        if c["id"] == category_id:
            return c
    return None

def _get_product_by_id(product_id: int):
    for p in PRODUCTS:
        if p["id"] == product_id:
            return p
    return None

def _get_product_by_sku(sku: str):
    sku_l = (sku or "").strip().lower()
    for p in PRODUCTS:
        if p["sku"].lower() == sku_l:
            return p
    return None

def _get_category_by_slug(slug: str):
    slug_l = (slug or "").strip().lower()
    for c in CATEGORIES:
        if c["slug"].lower() == slug_l:
            return c
    return None

def _filter_products(
    category_id=None,
    category_slug=None,
    in_stock=None,
    min_price=None,
    max_price=None,
    search=None,
    tags=None,
):
    items = PRODUCTS[:]

    if category_id is not None:
        items = [p for p in items if p["category_id"] == category_id]

    if category_slug is not None:
        cat = _get_category_by_slug(category_slug)
        if not cat:
            return []
        items = [p for p in items if p["category_id"] == cat["id"]]

    if in_stock is not None:
        items = [p for p in items if bool(p["in_stock"]) == bool(in_stock)]

    if min_price is not None:
        items = [p for p in items if float(p["price"]) >= float(min_price)]

    if max_price is not None:
        items = [p for p in items if float(p["price"]) <= float(max_price)]

    if search:
        s = search.strip().lower()
        items = [
            p
            for p in items
            if s in p["name"].lower()
            or s in (p.get("description") or "").lower()
            or s in p["sku"].lower()
        ]

    if tags:
        tagset = {t.strip().lower() for t in tags if t and t.strip()}
        if tagset:
            items = [
                p
                for p in items
                if tagset.issubset({t.lower() for t in (p.get("tags") or [])})
            ]

    return items

def _filter_reviews(product_id=None, user_id=None, min_rating=None, max_rating=None, limit=None, offset=None):
    items = REVIEWS[:]

    if product_id is not None:
        items = [r for r in items if r["product_id"] == product_id]

    if user_id is not None:
        items = [r for r in items if r["user_id"] == user_id]

    if min_rating is not None:
        items = [r for r in items if int(r["rating"]) >= int(min_rating)]

    if max_rating is not None:
        items = [r for r in items if int(r["rating"]) <= int(max_rating)]

    items.sort(key=lambda r: r.get("created_at") or "", reverse=True)

    if offset:
        items = items[int(offset):]

    if limit is not None:
        items = items[: int(limit)]

    return items

