class CategoryType(ObjectType):
    id = Int(required=True)
    name = String(required=True)
    slug = String(required=True)
    description = String()

    product_count = Int(required=True)

    def resolve_product_count(parent, info):
        cid = parent["id"] if isinstance(parent, dict) else getattr(parent, "id", None)
        return sum(1 for p in PRODUCTS if p["category_id"] == cid)

class ReviewType(ObjectType):
    id = Int(required=True)
    product_id = Int(required=True)
    user_id = Int(required=True)
    username = String(required=True)
    rating = Int(required=True)
    title = String()
    body = String()
    created_at = String(required=True)
    verified_purchase = Boolean(required=True)

    product = Field(lambda: ProductType, required=True)

    def resolve_product(parent, info):
        pid = parent["product_id"] if isinstance(parent, dict) else getattr(parent, "product_id", None)
        return _get_product_by_id(pid)

class ProductType(ObjectType):
    id = Int(required=True)
    sku = String(required=True)
    name = String(required=True)
    description = String()
    price = Float(required=True)
    currency = String(required=True)
    in_stock = Boolean(required=True)
    tags = List(String, required=True)

    category = Field(CategoryType, required=True)
    reviews = List(
        ReviewType,
        limit=Argument(Int),
        offset=Argument(Int),
        min_rating=Argument(Int),
        max_rating=Argument(Int),
    )
    review_count = Int(required=True)
    average_rating = Float()

    def resolve_category(parent, info):
        cid = parent["category_id"] if isinstance(parent, dict) else getattr(parent, "category_id", None)
        return _get_category_by_id(cid)

    def resolve_reviews(parent, info, limit=None, offset=None, min_rating=None, max_rating=None):
        pid = parent["id"] if isinstance(parent, dict) else getattr(parent, "id", None)
        return _filter_reviews(
            product_id=pid,
            min_rating=min_rating,
            max_rating=max_rating,
            limit=limit,
            offset=offset,
        )

    def resolve_review_count(parent, info):
        pid = parent["id"] if isinstance(parent, dict) else getattr(parent, "id", None)
        return sum(1 for r in REVIEWS if r["product_id"] == pid)

    def resolve_average_rating(parent, info):
        pid = parent["id"] if isinstance(parent, dict) else getattr(parent, "id", None)
        ratings = [int(r["rating"]) for r in REVIEWS if r["product_id"] == pid]
        if not ratings:
            return None
        return sum(ratings) / float(len(ratings))

