class Query(ObjectType):
    # Products
    product = Field(ProductType, id=Argument(Int), sku=Argument(String))
    products = List(
        ProductType,
        category_id=Argument(Int),
        category_slug=Argument(String),
        in_stock=Argument(Boolean),
        min_price=Argument(Float),
        max_price=Argument(Float),
        search=Argument(String),
        tags=Argument(List(String)),
        limit=Argument(Int),
        offset=Argument(Int),
    )

    # Categories
    category = Field(CategoryType, id=Argument(Int), slug=Argument(String))
    categories = List(CategoryType)

    # Reviews
    review = Field(ReviewType, id=Argument(Int, required=True))
    reviews = List(
        ReviewType,
        product_id=Argument(Int),
        user_id=Argument(Int),
        min_rating=Argument(Int),
        max_rating=Argument(Int),
        limit=Argument(Int),
        offset=Argument(Int),
    )

    # Simple health/info
    api_info = Field(String, required=True)

    def resolve_product(parent, info, id=None, sku=None):
        if id is not None:
            return _get_product_by_id(int(id))
        if sku is not None:
            return _get_product_by_sku(sku)
        return None

    def resolve_products(
        parent,
        info,
        category_id=None,
        category_slug=None,
        in_stock=None,
        min_price=None,
        max_price=None,
        search=None,
        tags=None,
        limit=None,
        offset=None,
    ):
        items = _filter_products(
            category_id=category_id,
            category_slug=category_slug,
            in_stock=in_stock,
            min_price=min_price,
            max_price=max_price,
            search=search,
            tags=tags,
        )
        if offset:
            items = items[int(offset):]
        if limit is not None:
            items = items[: int(limit)]
        return items

    def resolve_category(parent, info, id=None, slug=None):
        if id is not None:
            return _get_category_by_id(int(id))
        if slug is not None:
            return _get_category_by_slug(slug)
        return None

    def resolve_categories(parent, info):
        return CATEGORIES

    def resolve_review(parent, info, id):
        rid = int(id)
        for r in REVIEWS:
            if r["id"] == rid:
                return r
        return None

    def resolve_reviews(parent, info, product_id=None, user_id=None, min_rating=None, max_rating=None, limit=None, offset=None):
        return _filter_reviews(
            product_id=product_id,
            user_id=user_id,
            min_rating=min_rating,
            max_rating=max_rating,
            limit=limit,
            offset=offset,
        )

    def resolve_api_info(parent, info):
        return f"ecommerce-catalog-graphql | {datetime.utcnow().isoformat()}Z"

schema = Schema(query=Query)  # Introspection enabled by default

